import{c as r,Q as t,j as o,m as i}from"./chunks/framework.CJeKecSK.js";const a="/main/diagrams/kube-to-kube-provider.svg",n="/main/diagrams/p2p-kube-bind.svg",v=JSON.parse('{"title":"Provider to provider","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/interaction-patterns/provider-to-provider.md","filePath":"concepts/interaction-patterns/provider-to-provider.md"}'),s={name:"concepts/interaction-patterns/provider-to-provider.md"};function d(p,e,c,h,l,m){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="provider-to-provider" tabindex="-1">Provider to provider <a class="header-anchor" href="#provider-to-provider" aria-label="Permalink to &quot;Provider to provider&quot;">​</a></h1><p>The provider-to-provider pattern describes one service provider consuming another provider&#39;s API and composing it into its own service offering.</p><p>Use this pattern when a provider needs an upstream capability, such as certificates, storage, networking, billing, compliance checks, or another internal service, to fulfill its own consumer-facing API.</p><h2 id="participating-personas" tabindex="-1">Participating personas <a class="header-anchor" href="#participating-personas" aria-label="Permalink to &quot;Participating personas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Persona</th><th>Role in the pattern</th></tr></thead><tbody><tr><td>Platform owner</td><td>Provides the shared mesh, account model, and authorization boundaries that allow provider accounts to interact safely.</td></tr><tr><td>Upstream service provider</td><td>Publishes the capability consumed by another provider.</td></tr><tr><td>Composing service provider</td><td>Consumes the upstream API and exposes a higher-level or bundled capability to its own consumers.</td></tr><tr><td>Service consumer</td><td>Uses the composed provider API without needing to understand the upstream dependency graph.</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>The composing provider acts as a consumer of an upstream provider API. It can bind or consume that API through Platform Mesh, reconcile the upstream resources it needs, and expose its own API as a separate service offering.</p><p><img src="'+a+'" alt="Kube to Kube provider diagram"></p><p>This keeps provider implementation details behind provider boundaries. Consumers of the composed service interact with one provider API, while the composing provider manages any upstream provider dependencies.</p><p>If the provider-to-provider relationship needs APIs projected into Kubernetes clusters, kube-bind can be part of the flow.</p><p><img src="'+n+'" alt="Provider to provider kube-bind diagram"></p><h2 id="ownership-boundaries" tabindex="-1">Ownership boundaries <a class="header-anchor" href="#ownership-boundaries" aria-label="Permalink to &quot;Ownership boundaries&quot;">​</a></h2><p>Each provider owns its own API contract and runtime automation. The composing provider owns the dependency on the upstream capability. The upstream provider owns fulfillment and status for its own service.</p><p>Platform Mesh mediates the relationship through accounts, workspaces, identity, authorization, and declarative APIs. It does not collapse the two providers into one operational domain.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./provider-to-consumer.html">Provider to consumer</a></li><li><a href="./cross-consumption.html">Cross-consumption</a></li><li><a href="./../integration-paths.html">Integration paths</a></li><li><a href="./../api-sharing.html">API sharing</a></li></ul>',16)])])}const b=r(s,[["render",d]]);export{v as __pageData,b as default};
